package filters

import (
	"context"

	"github.com/openmeterio/openmeter/openmeter/entitlement"
)

var _ NamedFilter = (*ArchivedFeatureFilter)(nil)

type ArchivedFeatureFilter struct {
	entSvc entitlement.Service
}

func (f *ArchivedFeatureFilter) Name() string { return "archived_feature" }

func (f *ArchivedFeatureFilter) IsNamespaceInScope(ctx context.Context, ns string) (bool, error) {
	return true, nil
}

func (f *ArchivedFeatureFilter) IsEntitlementInScope(ctx context.Context, req EntitlementFilterRequest) (bool, error) {
	if err := req.Validate(); err != nil {
		return false, err
	}
	// check if feature is active; return false if archived
	return true, nil
}
